{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream bounded contexts that consume shipment data, and external partner integrations. This is not a simple schema migration — it redefines what a 'Shipment' means in the business.",
    "bounded_context": "Shipment Management (core domain). Ripple effects into: Routing & Dispatch, Notifications, Billing, Partner Integration, and Tracking.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more recipients. The aggregate root that owns the delivery lifecycle." },
      { "term": "Recipient", "definition": "A party who receives a delivery. Identified by name, address, phone number, and now also delivery preferences. A Shipment contains 1..N Recipients." },
      { "term": "Delivery Preferences", "definition": "Per-recipient instructions governing how delivery should occur (e.g., time window, signature required, safe place authorization, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a shipment. For backward compatibility, legacy shipments have exactly one recipient who is implicitly the primary." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with more than one recipient. May represent split deliveries, gift shipments, or distribution runs." },
      { "term": "Delivery Stop", "definition": "A discrete delivery point on a route, corresponding to one Recipient's address within a multi-recipient shipment." },
      { "term": "Shipment Status", "definition": "The lifecycle state of the shipment. In multi-recipient scenarios, this must now account for partial completion (some recipients delivered, others pending)." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment with no recipient is a logical impossibility — there is no delivery without someone to deliver to. This is a physical and data integrity constraint.",
      "testable_assertion": "Creating or updating a Shipment to have an empty Recipients collection must be rejected at the domain layer."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically execute a delivery and contact the recipient. Without them, the courier cannot operate.",
      "testable_assertion": "Attempting to add a Recipient with a null/empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment MAY have independent delivery preferences. If none are specified, system defaults apply.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy layer. The business may change default preferences, add new preference types, or make preferences mandatory — these are policy decisions, not integrity constraints.",
      "testable_assertion": "A Recipient added without explicit delivery preferences must be assigned system default preferences. A Recipient with explicit preferences must have those preferences respected during dispatch."
    },
    {
      "id": "BR-4",
      "rule": "Shipment status must reflect the aggregate delivery state across ALL recipients. A Shipment is 'Delivered' only when ALL recipients have received their delivery.",
      "invariant": true,
      "invariant_justification": "Reporting a shipment as delivered when some recipients have not received their goods would corrupt business state and violate the fundamental meaning of 'delivered'.",
      "testable_assertion": "A Shipment with 3 Recipients where only 2 have been delivered must have status 'Partially Delivered' or equivalent — never 'Delivered'."
    },
    {
      "id": "BR-5",
      "rule": "Existing single-recipient shipments (≈2M records) must remain valid and queryable without data loss or behavioral change after migration.",
      "invariant": true,
      "invariant_justification": "Data integrity of production records is non-negotiable. Existing business operations, audits, and partner integrations depend on these records being correct and accessible.",
      "testable_assertion": "After migration, querying any existing shipment must return exactly the same recipient data as before, now represented as a collection of one."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs must continue to receive shipment data they can parse. Partners consuming the single-recipient format must not break.",
      "invariant": true,
      "invariant_justification": "Breaking partner integrations causes contractual violations, revenue loss, and operational disruption. Partners cannot be forced to upgrade simultaneously.",
      "testable_assertion": "Partners subscribed to the v1 API format must receive shipment payloads with a single recipient field (primary recipient) until they migrate to the v2 format."
    },
    {
      "id": "BR-7",
      "rule": "A new shipment status — 'Partially Delivered' — must exist to represent the state where at least one but not all recipients have been delivered to.",
      "invariant": false,
      "invariant_justification": "The specific status naming and granularity is a business policy decision. The invariant is BR-4 (correctness of aggregate status); this rule is the policy implementation of that invariant.",
      "testable_assertion": "When 1 of N recipients (N > 1) is delivered, shipment status transitions to 'Partially Delivered'. When all N are delivered, status transitions to 'Delivered'."
    },
    {
      "id": "BR-8",
      "rule": "Each Recipient within a multi-recipient Shipment must be individually trackable with its own delivery status and proof of delivery.",
      "invariant": true,
      "invariant_justification": "Without per-recipient tracking, the system cannot determine aggregate shipment status (BR-4), handle failed deliveries to individual recipients, or provide proof of delivery — all of which are core logistics requirements.",
      "testable_assertion": "Each Recipient entity must have its own status field (e.g., Pending, Out for Delivery, Delivered, Failed) and optional proof-of-delivery record."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The sender specifies 3 recipients with different addresses and delivery preferences",
      "then": "The Shipment is created with 3 Recipient entries, each preserving their individual address, phone, name, and delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment from before the migration",
      "when": "The Shipment is queried via the API",
      "then": "It returns with a Recipients collection containing exactly one entry with the original recipient data intact"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where 2 of 3 recipients have been delivered",
      "when": "The shipment status is evaluated",
      "then": "The shipment status is 'Partially Delivered', not 'Delivered'"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment exists",
      "when": "An external partner using the v1 API requests this shipment's data",
      "then": "The response returns the primary recipient in the legacy single-recipient format without errors"
    },
    {
      "id": "AC-5",
      "given": "A Shipment is being created",
      "when": "The Recipients list is empty",
      "then": "The system rejects the creation with a validation error"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment where one recipient's delivery fails",
      "when": "The courier marks that specific recipient as 'Failed'",
      "then": "Only that recipient's status changes to 'Failed'; other recipients' statuses are unaffected, and the shipment-level status reflects the mixed state"
    },
    {
      "id": "AC-7",
      "given": "A Recipient is being added to a Shipment",
      "when": "No delivery preferences are specified",
      "then": "System default delivery preferences are applied to that Recipient"
    },
    {
      "id": "AC-8",
      "given": "All recipients on a multi-recipient Shipment have status 'Delivered'",
      "when": "The shipment status is evaluated",
      "then": "The shipment status transitions to 'Delivered'"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient shipment where two recipients share the same address but have different delivery preferences",
      "expected_behavior": "Both recipients are treated as distinct delivery stops with their own preferences honored. The system must not deduplicate by address."
    },
    {
      "scenario": "Recipient is removed from a multi-recipient shipment, leaving zero recipients",
      "expected_behavior": "Rejection. BR-1 invariant enforced — a shipment cannot have zero recipients. The removal must be blocked."
    },
    {
      "scenario": "Partner API v1 consumer requests a multi-recipient shipment",
      "expected_behavior": "The v1 adapter returns the primary recipient only. The response must include a deprecation header or equivalent signal encouraging migration to v2."
    },
    {
      "scenario": "A shipment has 50 recipients — what is the upper bound?",
      "expected_behavior": "A business-defined maximum must be established. Without it, unbounded recipient lists could cause routing failures, performance degradation, and impractical delivery runs. This needs a policy decision (see escalations)."
    },
    {
      "scenario": "Migration runs on 2M existing records while the system is live and new shipments are being created",
      "expected_behavior": "Migration must be backward-compatible (additive schema change). Existing records should work with both old and new code paths during the rollout window. Dual-write or lazy migration strategies should be evaluated."
    },
    {
      "scenario": "Billing: who pays for a multi-recipient shipment?",
      "expected_behavior": "Billing model must be clarified — is it per-shipment or per-recipient/stop? This fundamentally changes pricing and must be decided before implementation (see escalations)."
    },
    {
      "scenario": "Notification delivery: one recipient's phone number is invalid",
      "expected_behavior": "Notification failure for one recipient must not block notifications to other recipients. Each recipient's notification lifecycle is independent."
    },
    {
      "scenario": "Proof of delivery: some recipients require signature, others don't",
      "expected_behavior": "Per-recipient delivery preferences must be enforced independently. The courier app must present the correct proof-of-delivery flow for each stop."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments require a new billing model (per-stop vs per-shipment pricing). Revenue opportunity: consolidated multi-drop shipments could increase order volume and average shipment value. Risk: incorrect billing logic could lead to revenue leakage or customer disputes. Migration cost is non-trivial across 2M records.",
    "operational": "HIGH. Routing algorithms must be updated to optimize multi-stop routes. Courier dispatch logic changes fundamentally — a single shipment now generates multiple delivery tasks. Warehouse operations may need to support split-packing. Support teams need training on new shipment states (Partially Delivered).",
    "user": "MEDIUM-HIGH. Senders get more flexibility (gift shipments, distribution). Recipients get personalized delivery preferences. Couriers face more complex delivery runs. Risk: if partially-delivered states are not clearly communicated, confusion increases for all parties.",
    "risk": "HIGH. This is a core domain model change touching the Shipment aggregate root. Risks include: data migration failures on 2M records, partner API breakage, routing algorithm regressions, billing model gaps, and the introduction of the complex 'Partially Delivered' lifecycle state. Rollback would be extremely difficult once multi-recipient shipments exist in production.",
    "stakeholders_affected": [
      { "group": "Senders/Customers", "impact": "Gain ability to ship to multiple recipients in one shipment. Must understand new statuses and potentially new pricing." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. No negative impact if implemented correctly." },
      { "group": "Couriers/Drivers", "impact": "Delivery workflow becomes more complex — multiple stops per shipment with different proof-of-delivery requirements. Courier app must be updated." },
      { "group": "External Partners (API consumers)", "impact": "CRITICAL. Must not break. Requires API versioning strategy and migration timeline. Partners on v1 must be supported for a deprecation period." },
      { "group": "Operations/Dispatch", "impact": "Route optimization algorithms need multi-stop support. Dispatch logic must handle partial failures." },
      { "group": "Finance/Billing", "impact": "Billing model must be redefined. Per-shipment pricing may no longer be appropriate." },
      { "group": "Customer Support", "impact": "New shipment states and per-recipient tracking increase support complexity. Training and tooling updates required." },
      { "group": "Engineering", "impact": "Schema migration, API versioning, event schema changes, routing algorithm updates, courier app updates — broad cross-cutting change." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically incomplete. Two major business decisions are undefined: (1) the billing model for multi-recipient shipments, and (2) the upper bound on recipients per shipment. The partner API backward-compatibility strategy is implied but not specified. The concept of 'delivery preferences' is introduced without enumeration of what preferences are supported. These gaps mean acceptance criteria cannot be fully locked down.",
    "high_confidence_areas": [
      "1:N Recipient relationship is the correct model evolution",
      "Existing 2M records must be preserved with backward compatibility",
      "Per-recipient delivery status tracking is required",
      "Partner API versioning is mandatory",
      "A 'Partially Delivered' aggregate state is needed"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient shipments (per-shipment vs per-stop)",
      "Maximum recipients per shipment",
      "Exact set of supported delivery preferences",
      "Primary recipient designation rules for multi-recipient shipments",
      "Partner API deprecation timeline and migration support scope"
    ],
    "assumptions": [
      "Multi-recipient means multiple delivery addresses (not multiple contacts at one address)",
      "All recipients within a shipment originate from the same sender/origin",
      "The existing 'Delivered' status semantic changes to require all recipients delivered",
      "Partner API v1 will be maintained for a deprecation period rather than force-upgraded"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The billing model for multi-recipient shipments is undefined. Is a multi-recipient shipment priced as one shipment, or per-recipient/per-stop? This fundamentally affects the financial model and must be decided before implementation.",
      "affected_stakeholders": ["Finance/Billing", "Senders/Customers", "Product"],
      "options": [
        "A) Per-shipment flat rate (simpler, but may underprice multi-stop runs)",
        "B) Base rate + per-recipient surcharge (reflects true cost, more complex)",
        "C) Per-stop pricing (each recipient is essentially a separate delivery charge)"
      ],
      "recommendation": "Option B — base + surcharge — as it reflects the real operational cost while still incentivizing consolidation over separate shipments."
    },
    {
      "type": "ambiguity",
      "description": "No upper bound specified for recipients per shipment. Without a limit, a shipment with 1,000 recipients could break routing, overload courier apps, and create impractical delivery runs.",
      "affected_stakeholders": ["Operations/Dispatch", "Couriers/Drivers", "Engineering"],
      "options": [
        "A) Hard limit of 10 recipients per shipment",
        "B) Hard limit of 25 recipients per shipment",
        "C) Soft limit configurable per customer tier"
      ],
      "recommendation": "Option C — configurable per tier — with a sensible system-wide hard cap (e.g., 50) to prevent abuse while allowing enterprise customers flexibility."
    },
    {
      "type": "ambiguity",
      "description": "'Delivery preferences' is introduced as a concept but not defined. What preferences are supported? Time windows? Signature requirements? Safe place? Contactless? The domain model cannot be finalized without enumerating these.",
      "affected_stakeholders": ["Product", "Recipients", "Couriers/Drivers"],
      "options": [
        "A) Define a minimal set now (time window, signature required, safe place) and extend later",
        "B) Define a fully extensible key-value preference model from day one"
      ],
      "recommendation": "Option A — start with a well-defined minimal set. Extensibility can be added, but a vague schema from day one leads to inconsistent data."
    },
    {
      "type": "missing_context",
      "description": "Partner API contract details are not provided. How many partners consume shipment data? What format versions exist? Are there SLAs governing breaking changes? Without this, the backward-compatibility strategy cannot be fully specified.",
      "affected_stakeholders": ["External Partners (API consumers)", "Engineering", "Business Development"],
      "options": [
        "A) Audit all partner integrations and define a versioning + deprecation plan before implementation",
        "B) Assume v1 compatibility adapter is sufficient and address partner concerns reactively"
      ],
      "recommendation": "Option A — proactive audit. Breaking partner integrations has contractual and revenue consequences that far outweigh the cost of an audit."
    }
  ],

  "rejection_reasons": []
}

